import{_ as t,a,b as o,c as i,d as n,e as d,f as r,g as s}from"./chunks/无关系记录重新申请.D_1qirb1.js";import{_ as l,o as h,c,a2 as p}from"./chunks/framework.DnrXFDHb.js";const q=JSON.parse('{"title":"Federated Distributed Index","description":"","frontmatter":{},"headers":[],"relativePath":"en/Other/federated-distributed-index.md","filePath":"en/Other/federated-distributed-index.md","lastUpdated":1781962217000}'),u={name:"en/Other/federated-distributed-index.md"};function b(f,e,m,y,g,x){return h(),c("div",null,[...e[0]||(e[0]=[p('<h1 id="federated-distributed-index" tabindex="-1">Federated Distributed Index <a class="header-anchor" href="#federated-distributed-index" aria-label="Permalink to &quot;Federated Distributed Index&quot;">​</a></h1><p>The federated distributed index lets multiple ImgBed sites share file lists with each other.</p><p>In simple terms:</p><ul><li>You can share selected folders from your site with others.</li><li>You can join another node and sync that node&#39;s shared file list into your admin panel.</li><li>Federated files are mainly for browsing, searching, and opening links. They are not re-uploaded to your own storage.</li></ul><h2 id="where-to-configure-it" tabindex="-1">Where To Configure It <a class="header-anchor" href="#where-to-configure-it" aria-label="Permalink to &quot;Where To Configure It&quot;">​</a></h2><p>Open:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Federated Distributed Index</span></span></code></pre></div><p><img src="'+t+`" alt="Local federation node" loading="lazy"></p><p>The page has three tabs:</p><table tabindex="0"><thead><tr><th>Tab</th><th>Purpose</th></tr></thead><tbody><tr><td>Local Node</td><td>Enable your node, confirm public domain, select shared folders, and update outbound index</td></tr><tr><td>Nodes I Joined</td><td>Manage other ImgBed nodes you have joined</td></tr><tr><td>Nodes Joining Me</td><td>Manage requests from others who want to join your node</td></tr></tbody></table><h2 id="first-time-setup" tabindex="-1">First-Time Setup <a class="header-anchor" href="#first-time-setup" aria-label="Permalink to &quot;First-Time Setup&quot;">​</a></h2><ol><li>Open <code>Local Node</code>.</li><li>Turn on <code>Enable</code>.</li><li>Select folders to share under <code>Sync folders</code>.</li><li>Click <code>Update Outbound Index</code>.</li><li>If ImgBed detects a domain change, confirm that the current domain is correct before continuing.</li></ol><p>You can select multiple sync folders.</p><p>If the sync folder list is empty, all folders are shared.</p><h2 id="local-node" tabindex="-1">Local Node <a class="header-anchor" href="#local-node" aria-label="Permalink to &quot;Local Node&quot;">​</a></h2><h3 id="public-domain" tabindex="-1">Public Domain <a class="header-anchor" href="#public-domain" aria-label="Permalink to &quot;Public Domain&quot;">​</a></h3><p>The public domain is the site URL other nodes use to access your node.</p><p>ImgBed detects this automatically. You do not need to type it manually. The first time you update the index, ImgBed asks you to confirm whether the current access URL is the production domain.</p><p>If you change domains later, updating the index will ask for confirmation again.</p><h3 id="sync-folders" tabindex="-1">Sync Folders <a class="header-anchor" href="#sync-folders" aria-label="Permalink to &quot;Sync Folders&quot;">​</a></h3><p>Sync folders decide which files are shared with federation nodes.</p><p>For example, if you select only:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/</span></span>
<span class="line"><span>/2/</span></span></code></pre></div><p>Other nodes can only see files in those two directories.</p><h3 id="update-outbound-index" tabindex="-1">Update Outbound Index <a class="header-anchor" href="#update-outbound-index" aria-label="Permalink to &quot;Update Outbound Index&quot;">​</a></h3><p>This updates the file list that other nodes can sync from you.</p><p>Use it when:</p><ul><li>You enable federation for the first time.</li><li>You upload files you want to share.</li><li>You change sync folders.</li><li>You change the public domain and need to confirm it.</li></ul><h2 id="nodes-i-joined" tabindex="-1">Nodes I Joined <a class="header-anchor" href="#nodes-i-joined" aria-label="Permalink to &quot;Nodes I Joined&quot;">​</a></h2><p><code>Nodes I Joined</code> is where you subscribe to other nodes.</p><p><img src="`+a+'" alt="Nodes I joined" loading="lazy"></p><h3 id="request-to-join-another-node" tabindex="-1">Request To Join Another Node <a class="header-anchor" href="#request-to-join-another-node" aria-label="Permalink to &quot;Request To Join Another Node&quot;">​</a></h3><ol><li>Ask the other owner for an invitation link.</li><li>Paste it into the input box.</li><li>Click <code>Request to Join</code>.</li><li>Wait for the other owner to approve it in their admin panel.</li></ol><p>After approval, the node status becomes approved.</p><h3 id="update-inbound-index" tabindex="-1">Update Inbound Index <a class="header-anchor" href="#update-inbound-index" aria-label="Permalink to &quot;Update Inbound Index&quot;">​</a></h3><p><code>Update Inbound Index</code> syncs file lists from nodes you have joined.</p><p>Use it when:</p><ul><li>The other owner has just approved your request.</li><li>The other owner tells you shared content has been updated.</li><li>You want to refresh all joined federation file lists.</li></ul><p>To update only one node, click <code>Update Index</code> on that node card.</p><p><img src="'+o+'" alt="Update index" loading="lazy"></p><h3 id="unsubscribe" tabindex="-1">Unsubscribe <a class="header-anchor" href="#unsubscribe" aria-label="Permalink to &quot;Unsubscribe&quot;">​</a></h3><p>If you no longer want to sync a node, click <code>Unsubscribe</code>.</p><p>After unsubscribing, that node&#39;s federated index is removed from your local site.</p><h2 id="nodes-joining-me" tabindex="-1">Nodes Joining Me <a class="header-anchor" href="#nodes-joining-me" aria-label="Permalink to &quot;Nodes Joining Me&quot;">​</a></h2><p><code>Nodes Joining Me</code> is where you handle requests from others.</p><p><img src="'+i+'" alt="Nodes joining me" loading="lazy"></p><h3 id="generate-an-invitation-link" tabindex="-1">Generate an Invitation Link <a class="header-anchor" href="#generate-an-invitation-link" aria-label="Permalink to &quot;Generate an Invitation Link&quot;">​</a></h3><ol><li>Make sure the local node is enabled.</li><li>Click <code>Update Outbound Index</code> at least once so ImgBed confirms the public domain.</li><li>Open <code>Nodes Joining Me</code>.</li><li>Click <code>Reset Invitation Link</code>.</li><li>Copy the invitation link and send it to the other owner.</li></ol><p>If the invitation link is empty, the public domain usually has not been confirmed yet. Go back to <code>Local Node</code> and click <code>Update Outbound Index</code>.</p><h3 id="handle-join-requests" tabindex="-1">Handle Join Requests <a class="header-anchor" href="#handle-join-requests" aria-label="Permalink to &quot;Handle Join Requests&quot;">​</a></h3><p>When someone submits a request, it appears in the <code>Nodes Joining Me</code> list.</p><table tabindex="0"><thead><tr><th>Action</th><th>Meaning</th></tr></thead><tbody><tr><td>Approve</td><td>Allows the other node to sync your shared file list</td></tr><tr><td>Reject</td><td>Refuses the join request</td></tr><tr><td>Delete</td><td>Removes a finished record</td></tr><tr><td>Check Status</td><td>Checks whether the other side still keeps this relationship</td></tr></tbody></table><p>After approval, the other side still needs to click <code>Update Inbound Index</code> before your shared files appear there.</p><p><img src="'+n+'" alt="Approve invited node" loading="lazy"></p><h2 id="messages" tabindex="-1">Messages <a class="header-anchor" href="#messages" aria-label="Permalink to &quot;Messages&quot;">​</a></h2><p>After a relationship is approved, click <code>Message</code> on the node card.</p><p>Messages are only for communication about the federation relationship. They do not change files, tags, directories, or permissions.</p><p><img src="'+d+'" alt="Messages" loading="lazy"></p><h2 id="viewing-federated-files" tabindex="-1">Viewing Federated Files <a class="header-anchor" href="#viewing-federated-files" aria-label="Permalink to &quot;Viewing Federated Files&quot;">​</a></h2><p>After sync completes, return to the admin file list.</p><p>At the top of the page, switch between local files and federated files. In federated files, you can browse synced content.</p><p>Federated files are mainly for viewing, searching, previewing, and copying links. They are not local files, so you cannot move, delete, retag, or back them up from your own site.</p><p><img src="'+r+'" alt="Federated files in admin" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="why-does-it-ask-me-to-reapply-because-there-is-no-relationship-record" tabindex="-1">Why Does It Ask Me To Reapply Because There Is No Relationship Record? <a class="header-anchor" href="#why-does-it-ask-me-to-reapply-because-there-is-no-relationship-record" aria-label="Permalink to &quot;Why Does It Ask Me To Reapply Because There Is No Relationship Record?&quot;">​</a></h3><p>This usually means the other side deleted you and removed the record, so your relationship can no longer be found. Submit a new join request.</p><p><img src="'+s+'" alt="Reapply when no relationship record exists" loading="lazy"></p><h3 id="why-can-t-i-see-files-after-joining" tabindex="-1">Why Can&#39;t I See Files After Joining? <a class="header-anchor" href="#why-can-t-i-see-files-after-joining" aria-label="Permalink to &quot;Why Can&#39;t I See Files After Joining?&quot;">​</a></h3><p>Check:</p><ol><li>The other owner has approved your request.</li><li>The other owner has clicked <code>Update Outbound Index</code>.</li><li>You have clicked <code>Update Inbound Index</code>.</li><li>The other owner&#39;s sync folders include the directories they want to share.</li></ol><h3 id="what-should-i-do-when-domain-change-is-detected" tabindex="-1">What Should I Do When Domain Change Is Detected? <a class="header-anchor" href="#what-should-i-do-when-domain-change-is-detected" aria-label="Permalink to &quot;What Should I Do When Domain Change Is Detected?&quot;">​</a></h3><p>If you are currently opening the admin panel through the production domain, confirm and continue.</p><p>If you are using a temporary address, cancel, reopen the admin panel using the production domain, then try again.</p><h3 id="what-does-an-empty-sync-folder-list-mean" tabindex="-1">What Does an Empty Sync Folder List Mean? <a class="header-anchor" href="#what-does-an-empty-sync-folder-list-mean" aria-label="Permalink to &quot;What Does an Empty Sync Folder List Mean?&quot;">​</a></h3><p>An empty sync folder list means all folders are shared.</p><p>To share only some directories, select those folders manually.</p><h3 id="difference-between-outbound-and-inbound-index-updates" tabindex="-1">Difference Between Outbound and Inbound Index Updates <a class="header-anchor" href="#difference-between-outbound-and-inbound-index-updates" aria-label="Permalink to &quot;Difference Between Outbound and Inbound Index Updates&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Button</th><th>Simple Meaning</th></tr></thead><tbody><tr><td>Update Outbound Index</td><td>Updates what others can sync from me</td></tr><tr><td>Update Inbound Index</td><td>Updates what I have synced from others</td></tr></tbody></table>',78)])])}const w=l(u,[["render",b]]);export{q as __pageData,w as default};
